import 'dart:convert';import '../models/import_check_result.dart';class ImportCheckService{ImportCheckResult check(String text){final messages=<String>[];final warnings=<String>[];try{final decoded=jsonDecode(text);if(decoded is! Map<String,Object?>){return const ImportCheckResult(ok:false,messages:['Input must be a JSON object.'],warnings:[]);}if(decoded['schemaVersion']!=1){messages.add('Unsupported or missing schemaVersion.');}for(final key in ['devicesJson','settingsJson','adapterMetadataJson']){if((decoded[key] as String?)?.trim().isEmpty??true){messages.add('Missing $key.');}}if(messages.isEmpty){messages.add('Import bundle structure looks valid.');}return ImportCheckResult(ok:messages.length==1&&messages.first.contains('valid'),messages:messages,warnings:warnings);}catch(error){return ImportCheckResult(ok:false,messages:['Invalid JSON.'],warnings:['$error']);}}}
